<!doctype html><html><head><meta charset="utf-8"><style>body{font-family:DejaVu Sans,sans-serif;color:#1f2937;font-size:12px}h1{margin:0}.meta{margin:20px 0}.right{text-align:right}table{width:100%;border-collapse:collapse}th,td{padding:8px;border-bottom:1px solid #ddd}th{background:#f3f4f6}.totals{margin-left:auto;width:45%;margin-top:20px}</style></head><body><h1>KiteLedger</h1><div class="right"><strong>{{ $invoice->invoice_number }}</strong><br>Issued: {{ optional($invoice->issue_date)->format('Y-m-d') }}<br>Due: {{ optional($invoice->due_date)->format('Y-m-d') }}</div><div class="meta"><strong>Bill to</strong><br>{{ data_get($invoice->billing_identity, 'legal_name') ?: data_get($invoice->billing_identity, 'company_name') }}<br>{{ data_get($invoice->billing_identity, 'email') }}<br>{{ data_get($invoice->billing_identity, 'address') }}</div><table><thead><tr><th>Description</th><th class="right">Qty</th><th class="right">Unit</th><th class="right">Amount</th></tr></thead><tbody>@foreach($invoice->lines as $line)<tr><td>{{ $line->description }}</td><td class="right">{{ $line->quantity }}</td><td class="right">{{ $invoice->currency }} {{ number_format($line->unit_amount,2) }}</td><td class="right">{{ $invoice->currency }} {{ number_format($line->amount,2) }}</td></tr>@endforeach</tbody></table><table class="totals"><tr><td>Subtotal</td><td class="right">{{ $invoice->currency }} {{ number_format($invoice->subtotal,2) }}</td></tr><tr><td>Discount</td><td class="right">{{ number_format($invoice->discount,2) }}</td></tr><tr><td>Tax</td><td class="right">{{ number_format($invoice->tax,2) }}</td></tr><tr><th>Total</th><th class="right">{{ $invoice->currency }} {{ number_format($invoice->total,2) }}</th></tr></table></body></html>
